@prefix cdi: <http://ddialliance.org/Specification/DDI-CDI/1.0/RDF/> .
@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode [ a cdi:LongStructureDataSet ] ;
            sh:resultMessage "A LongStructureDataSet should have physical mappings (cdi:hasPhysicalMapping) linking variables to columns." ;
            sh:resultPath cdi:hasPhysicalMapping ;
            sh:resultSeverity sh:Warning ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape [ sh:message "A LongStructureDataSet should have physical mappings (cdi:hasPhysicalMapping) linking variables to columns." ;
                    sh:minCount 1 ;
                    sh:path cdi:hasPhysicalMapping ;
                    sh:severity sh:Warning ] ] .

@prefix sh: <http://www.w3.org/ns/shacl#> .
